import{_ as a,c as e,o as t,a1 as s}from"./chunks/framework.biRBrEtS.js";const q=JSON.parse('{"title":"NapCatQQ","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/getting-started.md","filePath":"zh-CN/guide/getting-started.md","lastUpdated":1714758134000}'),i={name:"zh-CN/guide/getting-started.md"},p=s(`<h1 id="napcatqq" tabindex="-1">NapCatQQ <a class="header-anchor" href="#napcatqq" aria-label="Permalink to &quot;NapCatQQ&quot;">​</a></h1><p>NapCatQQ 是基于 PC NTQQ 客户端本体实现的 QQ Bot 框架，稳定安全，快速部署。</p><h2 id="启动前需要了解的三两事" tabindex="-1">启动前需要了解的三两事 <a class="header-anchor" href="#启动前需要了解的三两事" aria-label="Permalink to &quot;启动前需要了解的三两事&quot;">​</a></h2><p><strong>（!你给我好好读三遍）</strong></p><ol><li><p>NapCat 是基于NT QQ 客户端本体实现的QQ Bot框架，所以说需要提前安装好和 <strong>NapCatQQ 对应的 QQ 版本</strong>才能运行 NapCat 哦</p></li><li><p>NapCat 在线时，你不能使用 PC QQ 客户端实现人鸡合一，但是可以选择同步登录移动客户端，如果想要在 PC 上人机合一请使用<a href="https://github.com/LLOneBot/LLOneBot" target="_blank" rel="noreferrer">LLOneBot</a></p></li><li><p>NapCat 不同于协议实现，是基于 QQ 客户端，QQ 客户端上干不了的事，NapCat &gt;_&lt; 当然也是不行的!</p></li></ol><h2 id="安装-qq" tabindex="-1">安装 QQ <a class="header-anchor" href="#安装-qq" aria-label="Permalink to &quot;安装 QQ&quot;">​</a></h2><p>NapCatQQ v1.2.0(beta) 版本对应的QQ： <a href="https://dldir1.qq.com/qqfile/qq/QQNT/5e09ff15/QQ9.9.9.23361_x64.exe" target="_blank" rel="noreferrer">Windows QQ 9.9.9-23361</a> | <a href="https://dldir1.qq.com/qqfile/qq/QQNT/Linux/QQ_3.2.7_240428_amd64_01.deb" target="_blank" rel="noreferrer">Linux QQ 2.3.7-23361</a></p><p>NapCatQQ v1.1.0 版本对应的QQ <a href="https://dldir1.qq.com/qqfile/qq/QQNT/Windows/QQ_9.9.9_240403_x64_01.exe" target="_blank" rel="noreferrer">Windows QQ 9.9.9-22741</a> | <a href="https://dldir1.qq.com/qqfile/qq/QQNT/Linux/QQ_3.2.7_240403_amd64_01.deb" target="_blank" rel="noreferrer">Linux QQ 2.3.7-22741</a></p><p>Linux 无需桌面安装 NTQQ:</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libgbm1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libasound2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./qq.deb</span></span></code></pre></div><p>更多版本请查看<a href="./version">版本更新记录</a></p><h2 id="下载napcatqq" tabindex="-1">下载NapCatQQ <a class="header-anchor" href="#下载napcatqq" aria-label="Permalink to &quot;下载NapCatQQ&quot;">​</a></h2><p>下载地址: <a href="https://github.com/NapNeko/NapCatQQ/releases" target="_blank" rel="noreferrer">https://github.com/NapNeko/NapCatQQ/releases</a></p><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>为了避免二次启动，可以事先配置好 NapCat 的基础设置，见 <a href="./config">如何配置NapCat</a></p><h2 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to &quot;启动&quot;">​</a></h2><details class="details custom-block"><summary>Windows</summary><p>安装好对应版本 QQ 后 我们大多数情况只需要解压 NapCat 放到你想的的任何地方，但是路径不能包含空格</p><p>双击 <code>napcat.bat</code> 就可以运行啦</p><p>等等! 如果你出现乱码可以尝试双击 <code>napcat-utf8.bat</code>启动</p><p>除了上面的方法你还可以使用 powershell 启动 NapCat（如果启动好了，就不用看下面的这种启动方式了）</p><p>启动powershell运行<code>powershell ./napcat.ps1</code>, 或者 <code>napcat.bat</code>，如果出现乱码，可以尝试运行<code>napcat-utf8.ps1</code> 或 <code>napcat-utf8.bat</code></p><p><em>如果出现 powershell 运行不了，可以尝试 <code>powershell.exe -ExecutionPolicy Bypass -File &quot;.\\napcat.ps1&quot;</code></em></p><p><strong>推荐使用 bat 运行，powershell 会自身占用 20MB 左右的内存</strong></p></details><details class="details custom-block"><summary>Linux Docker</summary><p><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">详细教程</a></p></details><details class="details custom-block"><summary>Linux 非 Docker</summary><p>运行<code>napcat.sh</code></p></details><details class="details custom-block"><summary>无需扫码快速登录</summary><p>如果你已经成功登录过官方 QQ 或者 NapCatQQ，可以加参数<code> -q &lt;你的QQ&gt;</code> 进行快速登录而无需扫码，如<code>napcat.bat -q 1234567</code> 或者 <code>napcat.sh -q 1234567</code></p></details><h3 id="启动之后" tabindex="-1">启动之后 <a class="header-anchor" href="#启动之后" aria-label="Permalink to &quot;启动之后&quot;">​</a></h3><p>恭喜你，如果看到这里，你可能已经启动或者尝试启动了 NapCat</p><p><a href="/zh-CN/guide/config">如何配置NapCat的基础设置</a></p><p><a href="/zh-CN/guide/faq">如何配置NapCat的语音发送</a> 参考 <code>语音、视频发送失败</code> 发生失败条目</p><p><a href="/zh-CN/guide/faq">遇到NapCat崩溃问题如何解决</a></p>`,25),r=[p];function l(o,n,d,h,c,Q){return t(),e("div",null,r)}const k=a(i,[["render",l]]);export{q as __pageData,k as default};
